def furthest_point(moves: str) -> int:
    n = len(moves)
    # Maximum possible distance to the right
    right = 0
    for c in moves:
        if c == 'R' or c == '_':
            right += 1
        else:
            right -= 1

    # Maximum possible distance to the left
    left = 0
    for c in moves:
        if c == 'L' or c == '_':
            left -= 1
        else:
            left += 1

    return max(abs(right), abs(left))
